import React from 'react'
import { Layout } from 'antd';
const { Header, Content, Footer, Sider } = Layout;
export default function Contacts() {
  return (
    <Content
      style={{
        padding: '0 50px',
        margin: "30px"
      }}
    >
      <Layout
        style={{
          height: "100%",
          padding: '24px 0',
          backgroundColor: "rgb(0,0,0)",
        }}
      >
        <Sider
          width={200}
          style={{
            backgroundColor: "transparent"
          }}
        >
        </Sider>
        <Content
          style={{
            padding: '0 24px',
            minHeight: 280,
          }}
        >
          Contacts
        </Content>
      </Layout>
    </Content>
  )
}
